const allRows = $('Parse Read Items').all();

// Filter to unprocessed rows (status column is empty/blank)
const unprocessed = allRows.filter(r => {
  const status = String(r.json.status || '').trim();
  return !status && String(r.json.company_name || '').trim() !== '';
});

// Check for duplicates within the unprocessed set
const seen = new Set();
const unique = [];
for (const row of unprocessed) {
  const name = String(row.json.company_name || '').toLowerCase().trim();
  if (!name || seen.has(name)) continue;
  seen.add(name);
  unique.push(row);
}

// Take first 5 rows for this batch
const batch = unique.slice(0, 5);

if (batch.length === 0) {
  return [{ json: { _skip: true, company_name: '' } }];
}

return batch.map(r => ({ json: { ...r.json, is_duplicate: false } }));

