// Extract clean domain from URL Validate response
const raw = String($('OpenRouter - URL Validate').first().json.choices[0].message.content || '').trim();

// Strip quotes, markdown, and whitespace the LLM may have added
const cleaned = raw.replace(/[`'"\[\]()]/g, '').replace(/\s+/g, '').trim();

// Extract domain: remove protocol, www, trailing path
let domain = cleaned
  .replace(/^https?:\/\//i, '')
  .replace(/^www\./i, '')
  .split('/')[0]
  .split('?')[0]
  .split('#')[0];

// Validate it looks like a domain
if (!domain || !domain.includes('.')) {
  domain = '';
}

return [{ json: { clean_domain: domain } }];

const picked = ($json.choices[0].message.content || '').trim();
const lower = String(picked).toLowerCase();

// Check if it's duplicate/none first
if (lower === 'duplicate' || lower === 'none' || !picked) {
  return [{ json: { best_url: picked } }];
}

// Check against ALL existing URLs (not just the 200 sent to LLM)
const allUrls = $('Prep URL Data').first().json.all_urls || [];
const pickedClean = picked.replace(/^https?:\/\//i, '').replace(/^www\./i, '').replace(/\/+$/, '').toLowerCase();

const isDuplicate = allUrls.some(function(u) {
  const existing = String(u).replace(/^https?:\/\//i, '').replace(/^www\./i, '').replace(/\/+$/, '').toLowerCase();
  return existing === pickedClean;
});

if (isDuplicate) {
  return [{ json: { best_url: 'duplicate' } }];
}

return [{ json: { best_url: picked } }];

const emails = ($json?.data?.emails || []);
// Priority: management > it > finance > operations
const priority = ['management', 'it', 'finance', 'operations'];
let best = null;
for (const dept of priority) {
  best = emails.find(e => e.department === dept && e.type === 'personal');
  if (best) break;
}
if (!best) best = emails.find(e => e.type === 'personal');
if (!best) best = emails[0];
if (!best) return [{ json: { first_name: '', role: '', email: '', linkedin_url: '', source: 'hunter' } }];
return [{ json: {
  first_name: best.first_name || '',
  role: best.position || '',
  email: best.value || '',
  linkedin_url: best.linkedin || '',
  source: 'hunter'
} }];

